{"output":"import { createContext, useCallback } from 'react'
import PropTypes from 'prop-types'
import axios from 'axios'
import { useQuery, useQueryClient } from 'react-query'
import { getQueryKeys } from 'lib/react-query-keys'
import { LoadingIndicatorWithContainer } from 'components/LoadingIndicator'
import SomethingWentWrong from 'components/SomethingWentWrong'

const AccountContext = createContext({})

const fetchServerData = async (path) => await axios.get(path)

const withAccountContext = (Component) => {
  const ComponentWithAccountContext = ({ uid, ...props }) => {
    const queryClient = useQueryClient()

    const path = `/org/v3/accounts/${uid}`
    const queryKeys = getQueryKeys(path)

    const { data, isError, isLoading } = useQuery(
      queryKeys,
      () => fetchServerData(path),
      {
        enabled: !!uid,
      }
    )

    const onAccountUpdate = useCallback(() => {
      queryClient.invalidateQueries(queryKeys)
    }, [queryClient, queryKeys])

    if (isError) return <SomethingWentWrong />

    if (isLoading) return <LoadingIndicatorWithContainer />

    return (
      <AccountContext.Provider value={{ account: data.data, onAccountUpdate }}>
        <Component {...props} onAccountUpdate={onAccountUpdate} />
      </AccountContext.Provider>
    )
  }

  ComponentWithAccountContext.propTypes = {
    uid: PropTypes.string,
  }

  return ComponentWithAccountContext
}

const withURLAccountId = (Component) => {
  const ComponentWithURLAccountId = (props) => {
    const uid = window.location.pathname.split('/')[2]

    return <Component {...props} uid={uid} />
  }

  return ComponentWithURLAccountId
}

const withAccountContextWithURLAccountID = (Component) =>
  withURLAccountId(withAccountContext(Component))

export default AccountContext
export { withAccountContextWithURLAccountID as withAccountContext }
